class Solution {
    public int shortestMatchingSubstring(String s, String p) {
        int n = s.length(), m = p.length();
        int[][] dp = new int[n + 1][m + 1];
        for (int i = 0; i <= n; i++) {
            Arrays.fill(dp[i], n + 1);
        }
        dp[0][0] = 0;
        int star1 = p.indexOf('*');
        int star2 = p.lastIndexOf('*');
        for (int i = 0; i <= n; i++) {
            for (int j = 0; j <= m; j++) {
                if (j == 0) {
                    if (i == 0) continue;
                    dp[i][j] = n + 1;
                } else if (p.charAt(j - 1) == '*') {
                    dp[i][j] = Math.min(dp[i][j], dp[i][j - 1]);
                    if (j == star1 + 1 || j == star2 + 1) {
                        if (i > 0) dp[i][j] = Math.min(dp[i][j], dp[i - 1][j - 1]);
                    } else {
                        if (i > 0 && s.charAt(i - 1) == p.charAt(j - 1)) dp[i][j] = Math.min(dp[i][j], dp[i - 1][j - 1]);
                    }
                } else {
                    if (i > 0 && s.charAt(i - 1) == p.charAt(j - 1)) dp[i][j] = Math.min(dp[i][j], dp[i - 1][j - 1] + 1);
                }
            }
        }
        int res = dp[n][m];
        return res > n ? -1 : res;
    }
}
